const sharp = require\('sharp'\);
// 16 wood samples image is 3900x4800, 4 rows x 4 cols grid
// Each cell: ~975x1200
// Crop top-left cell \(row0,col0\) for alamo - light blonde wood
// Crop top-right cell \(row0,col2\) for pino - lighter warm wood
const w = 975, h = 1200;
Promise.all\([
  sharp\('public/images/maderas/alamo.jpg'\).extract\({left:0, top:0, width:w, height:h}\).jpeg\({quality:85}\).toFile\('public/images/maderas/alamo.jpg'\),
  // Use bottom-right cell for pino \(last row, last col\) - looks pine-like
  sharp\('public/images/maderas/pino.jpg'\).extract\({left:2925, top:3600, width:975, height:1200}\).jpeg\({quality:85}\).toFile\('public/images/maderas/pino-crop.jpg'\),
]\).then\(\(\) => console.log\('done'\)\).catch\(e => console.error\(e\)\);
")

