const sharp = require\('sharp'\);

async function run\(\) {
  // Get conifer image dimensions to crop 3rd and 4th samples \(cypress-like\)
  const conifer = await sharp\('conifer-dl.jpg'\).metadata\(\);
  console.log\('conifer:', conifer.width, 'x', conifer.height\);
  const w4 = Math.floor\(conifer.width / 4\);

  // Crop 3rd sample \(index 2\) = Western Red Cedar \(reddish, similar to cypress\)
  await sharp\('conifer-dl.jpg'\)
    .extract\({ left: w4 * 2, top: 0, width: w4, height: conifer.height }\)
    .resize\(600, 400, { fit: 'cover' }\)
    .jpeg\({ quality: 85 }\)
    .toFile\('cipres-new.jpg'\);
  console.log\('cipres-new.jpg done'\);

  // Crop locust end grain - it's a beautiful golden end grain texture
  await sharp\('locust-dl.jpg'\)
    .resize\(600, 400, { fit: 'cover' }\)
    .jpeg\({ quality: 85 }\)
    .toFile\('acacia-new.jpg'\);
  console.log\('acacia-new.jpg done'\);

  // Crop eiche \(oak\) cross-section center - has beautiful growth rings
  const eiche = await sharp\('eiche-dl.jpg'\).metadata\(\);
  console.log\('eiche:', eiche.width, 'x', eiche.height\);
  await sharp\('eiche-dl.jpg'\)
    .resize\(600, 400, { fit: 'cover' }\)
    .jpeg\({ quality: 85 }\)
    .toFile\('roble-new.jpg'\);
  console.log\('roble-new.jpg done'\);
}
run\(\).catch\(console.error\);
")

